document.addEventListener("DOMContentLoaded", () => {const body = document.body;const html = document.documentElement;const themeToggle = document.getElementById("themeToggle");const navToggle = document.getElementById("navToggle");const navLinks = document.getElementById("navLinks");const applyTheme = (theme) => {const isLight = theme === "light";html.classList.remove("theme-light", "theme-dark");body.classList.remove("theme-light", "theme-dark");html.classList.add(`theme-${theme}`);body.classList.add(`theme-${theme}`);if (themeToggle) {themeToggle.textContent = isLight ? "☀️" : "🌙";themeToggle.setAttribute("aria-label",isLight? "Darstellung auf dunkel wechseln": "Darstellung auf hell wechseln");themeToggle.setAttribute("aria-pressed", isLight ? "true" : "false");}};const getInitialTheme = () => {const savedTheme = window.localStorage.getItem("lumencat-theme");if (savedTheme === "light" || savedTheme === "dark") {return savedTheme;}const prefersLight =window.matchMedia &&window.matchMedia("(prefers-color-scheme: light)").matches;return prefersLight ? "light" : "dark";};const currentTheme = getInitialTheme();applyTheme(currentTheme);if (themeToggle) {themeToggle.addEventListener("click", () => {const isCurrentlyLight = body.classList.contains("theme-light");const nextTheme = isCurrentlyLight ? "dark" : "light";applyTheme(nextTheme);try {window.localStorage.setItem("lumencat-theme", nextTheme);} catch (e) {console.warn("Theme konnte nicht gespeichert werden:", e);}});}if (navToggle && navLinks) {const isOpenOnLoad = navLinks.classList.contains("nav__links--open");navToggle.setAttribute("aria-expanded", isOpenOnLoad ? "true" : "false");navToggle.addEventListener("click", () => {const isOpen = navLinks.classList.toggle("nav__links--open");navToggle.setAttribute("aria-expanded", isOpen ? "true" : "false");});navLinks.querySelectorAll("a").forEach((link) => {link.addEventListener("click", () => {navLinks.classList.remove("nav__links--open");navToggle.setAttribute("aria-expanded", "false");});});}const revealElements = document.querySelectorAll(".reveal, .reveal-fade");const prefersReducedMotion =window.matchMedia &&window.matchMedia("(prefers-reduced-motion: reduce)").matches;if (prefersReducedMotion || !("IntersectionObserver" in window)) {revealElements.forEach((el) => {el.classList.add("reveal--visible");});} else {const observer = new IntersectionObserver((entries, obs) => {entries.forEach((entry) => {if (entry.isIntersecting) {entry.target.classList.add("reveal--visible");const once = entry.target.getAttribute("data-reveal-once");if (once !== "false") {obs.unobserve(entry.target);}}});},{threshold: 0.16,});revealElements.forEach((el) => observer.observe(el));}const hero = document.querySelector(".hero");if (hero && !prefersReducedMotion) {const heroBg = hero.querySelector(".hero__bg img");if (heroBg) {let ticking = false;window.addEventListener("scroll", () => {if (!ticking) {window.requestAnimationFrame(() => {const scrollY = window.scrollY || window.pageYOffset;const offset = scrollY * 0.7;heroBg.style.transform = `translateY(${offset}px)`;ticking = false;});ticking = true;}});}}const contactForm = document.getElementById("contactForm");const contactHint = document.getElementById("contactHint");if (contactForm && contactHint) {const loadCsrfToken = async () => {const controller = new AbortController();const timeoutId = setTimeout(() => controller.abort(), 5000);try {const response = await fetch("scripts/csrf-token.php", {signal: controller.signal,});clearTimeout(timeoutId);const data = await response.json();if (data.success && data.csrf_token) {const csrfInput = document.getElementById("csrf_token");if (csrfInput) {csrfInput.value = data.csrf_token;}} else {console.error("CSRF token konnte nicht geladen werden");}} catch (error) {if (error.name === "AbortError") {console.error("CSRF token load timed out");} else {console.error("CSRF token load failed:", error);}}};loadCsrfToken();contactForm.addEventListener("submit", async (event) => {event.preventDefault();const emailInput = document.getElementById("email");const email = emailInput ? emailInput.value : "";const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;if (email && !emailRegex.test(email)) {contactHint.textContent = "Bitte gib eine gültige E-Mail-Adresse ein.";contactHint.style.color = "#ff9494";return;}contactHint.textContent = "Ich sende deine Nachricht...";contactHint.style.color = "";const formData = new FormData(contactForm);try {const response = await fetch(contactForm.action, {method: "POST",body: formData,});const data = await response.json();if (data.success) {contactHint.textContent =data.message || "Danke für deine Nachricht!";contactHint.style.color = "#19f7ff";contactForm.reset();await loadCsrfToken();} else {contactHint.textContent =data.message ||"Da ist etwas schiefgelaufen. Bitte prüf deine Eingaben.";contactHint.style.color = "#ff9494";}} catch (error) {console.error("Kontaktformular-Fehler:", error);contactHint.textContent ="Ich konnte deine Nachricht gerade nicht senden. Bitte versuch es später noch einmal oder schreib direkt an hello@lumencat.de.";contactHint.style.color = "#ff9494";}});}});